import React from 'react';
import { useParams, useNavigate } from 'react-router-dom';

const SemesterSelectionPage = () => {
  const { courseId, yearId } = useParams();
  const navigate = useNavigate();
  
  const semesters = [
    { number: 1, name: "Semester 1", subjects: 6, color: "#3B82F6" },
    { number: 2, name: "Semester 2", subjects: 6, color: "#10B981" },
    { number: 3, name: "Semester 3", subjects: 7, color: "#8B5CF6" },
    { number: 4, name: "Semester 4", subjects: 7, color: "#EF4444" },
    { number: 5, name: "Semester 5", subjects: 6, color: "#F59E0B" },
    { number: 6, name: "Semester 6", subjects: 6, color: "#EC4899" },
    { number: 7, name: "Semester 7", subjects: 5, color: "#6366F1" },
    { number: 8, name: "Semester 8", subjects: 5, color: "#14B8A6" }
  ];

  const handleSemesterClick = (semNumber) => {
    navigate(`/course/${courseId}/year/${yearId}/sem/${semNumber}`);
  };

  const handleBack = () => {
    navigate(`/course/${courseId}`);
  };

  return (
    <div style={styles.container}>
      <button style={styles.backButton} onClick={handleBack}>
        ← Back to Years
      </button>
      
      <header style={styles.header}>
        <h1>📅 Year {yearId}</h1>
        <p>Select your semester to view subjects</p>
      </header>

      <div style={styles.semestersGrid}>
        {semesters.map((sem) => (
          <div 
            key={sem.number} 
            style={{
              ...styles.semesterCard,
              background: `linear-gradient(135deg, ${sem.color}20, ${sem.color}40)`,
              borderLeft: `5px solid ${sem.color}`
            }}
            onClick={() => handleSemesterClick(sem.number)}
          >
            <div style={styles.semesterHeader}>
              <div style={styles.semesterNumber}>{sem.number}</div>
              <h3>{sem.name}</h3>
            </div>
            
            <div style={styles.semesterInfo}>
              <div style={styles.infoItem}>
                <span style={styles.infoLabel}>Subjects:</span>
                <span style={styles.infoValue}>{sem.subjects}</span>
              </div>
              <div style={styles.infoItem}>
                <span style={styles.infoLabel}>Credits:</span>
                <span style={styles.infoValue}>24-28</span>
              </div>
            </div>
            
            <div style={styles.materialsList}>
              <span style={styles.materialBadge}>Syllabus</span>
              <span style={styles.materialBadge}>Notes</span>
              <span style={styles.materialBadge}>PYQs</span>
              <span style={styles.materialBadge}>Lab Files</span>
            </div>
            
            <button style={styles.viewButton}>
              View Subjects →
            </button>
          </div>
        ))}
      </div>
    </div>
  );
};

const styles = {
  container: {
    maxWidth: '1200px',
    margin: '0 auto',
    padding: '2rem 1rem',
    minHeight: '100vh'
  },
  backButton: {
    padding: '0.75rem 1.5rem',
    background: '#6B7280',
    color: 'white',
    border: 'none',
    borderRadius: '8px',
    cursor: 'pointer',
    marginBottom: '2rem',
    fontSize: '1rem'
  },
  header: {
    textAlign: 'center',
    marginBottom: '3rem',
    padding: '2rem',
    background: 'white',
    borderRadius: '20px',
    boxShadow: '0 5px 15px rgba(0,0,0,0.05)'
  },
  semestersGrid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
    gap: '1.5rem'
  },
  semesterCard: {
    background: 'white',
    padding: '1.5rem',
    borderRadius: '15px',
    cursor: 'pointer',
    transition: 'all 0.3s',
    boxShadow: '0 5px 15px rgba(0,0,0,0.05)',
    '&:hover': {
      transform: 'translateY(-5px)',
      boxShadow: '0 15px 30px rgba(0,0,0,0.1)'
    }
  },
  semesterHeader: {
    display: 'flex',
    alignItems: 'center',
    gap: '1rem',
    marginBottom: '1rem'
  },
  semesterNumber: {
    width: '50px',
    height: '50px',
    background: 'white',
    borderRadius: '50%',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    fontSize: '1.5rem',
    fontWeight: 'bold',
    boxShadow: '0 3px 10px rgba(0,0,0,0.1)'
  },
  semesterInfo: {
    display: 'flex',
    gap: '1.5rem',
    margin: '1rem 0',
    fontSize: '0.9rem'
  },
  infoItem: {
    display: 'flex',
    flexDirection: 'column'
  },
  infoLabel: {
    color: '#666',
    fontSize: '0.8rem'
  },
  infoValue: {
    fontWeight: 'bold',
    fontSize: '1.1rem'
  },
  materialsList: {
    display: 'flex',
    flexWrap: 'wrap',
    gap: '0.5rem',
    margin: '1rem 0'
  },
  materialBadge: {
    background: 'rgba(255,255,255,0.8)',
    padding: '0.3rem 0.8rem',
    borderRadius: '15px',
    fontSize: '0.8rem',
    border: '1px solid rgba(0,0,0,0.1)'
  },
  viewButton: {
    marginTop: '1rem',
    padding: '0.75rem',
    width: '100%',
    background: 'rgba(255,255,255,0.9)',
    border: '1px solid rgba(0,0,0,0.1)',
    borderRadius: '8px',
    cursor: 'pointer',
    fontSize: '0.9rem',
    fontWeight: '500',
    transition: 'all 0.3s',
    '&:hover': {
      background: 'white',
      boxShadow: '0 5px 15px rgba(0,0,0,0.1)'
    }
  }
};

export default SemesterSelectionPage;
